mapper.select:
SELECT tbih.UTLINSTT_ID , tbih.INVM_STG_CD , ccd_stg.COM_CD_NM AS INVM_STG_NM , tbih.INVM_AMT_CD , ccd_amt.COM_CD_NM AS INVM_AMT_NM
, CASE WHEN tbih.OPPB_YN IS NULL THEN 'N' ELSE tbih.OPPB_YN END AS OPPB_YN , tbih.RGSN_USER_ID , tbih.RGSN_TS , tbih.AMNN_USER_ID , tbih.AMNN_TS
, CASE WHEN tbih.OSIV_HOPEYN IS NULL THEN 'N' ELSE tbih.OSIV_HOPEYN END AS OSIV_HOPEYN FROM TB_BOX_IVT_INVM_HOPE_D tbih LEFT JOIN TB_BOX_IVT_COM_CD_D ccd_stg ON ccd_stg.COM_CD_ID = tbih.INVM_STG_CD LEFT JOIN TB_BOX_IVT_COM_CD_D ccd_amt ON ccd_amt.COM_CD_ID = tbih.INVM_AMT_CD WHERE tbih.UTLINSTT_ID = #{utlinsttId}

mapper.insert:
MERGE INTO TB_BOX_IVT_ENPR_INFO_D tbieid
USING DUAL ON (tbieid.UTLINSTT_ID = #{utlinsttId})
WHEN MATCHED THEN
    UPDATE SET
        ATRW_STPL_COSN_YN = #{atrwStplCosnYn}
        , AMNN_USER_ID = #{amnnUserId}
        , AMNN_TS = CURRENT_TIMESTAMP
WHEN NOT MATCHED THEN
    INSERT
    (
        UTLINSTT_ID
        , ATRW_STPL_COSN_YN
        , RGSN_USER_ID
        , RGSN_TS
        , AMNN_USER_ID
        , AMNN_TS
    )
    VALUES
    (
        #{utlinsttId}
        , #{atrwStplCosnYn}
        , #{rgsnUserId}
        , CURRENT_TIMESTAMP
        , #{amnnUserId}
        , CURRENT_TIMESTAMP
    )

MERGE INTO TB_BOX_IVT_ENPR_INFO_D tbieid
USING DUAL ON (tbieid.UTLINSTT_ID = #{utlinsttId})
WHEN MATCHED THEN
    UPDATE SET
        ENFM_CLSF_CD      = #{enfmClsfCd}
        , ENPR_DSNC_CLSF_CD = #{enprDsncClsfCd}
        , BSUN_DWAR_CD      = #{bsunDwarCd}
        , EMP_CNT           = #{empCnt}
        , BTNM              = #{btnm}
        , BZST_NM           = #{bzstNm}
        , MSRN_AMSL_YEAR    = #{msrnAmslYear}
        , MSRN_AMSL_AMT     = #{msrnAmslAmt}
        , LSTN_YN           = #{lstnYn}
        , ENPR_INRD_CON     = #{enprInrdCon}
        , AMNN_USER_ID      = #{amnnUserId}
        , AMNN_TS           = CURRENT_TIMESTAMP
WHEN NOT MATCHED THEN
    INSERT
    (
        UTLINSTT_ID
        , ENFM_CLSF_CD
        , ENPR_DSNC_CLSF_CD
        , BSUN_DWAR_CD
        , EMP_CNT
        , BTNM
        , BZST_NM
        , MSRN_AMSL_YEAR
        , MSRN_AMSL_AMT
        , LSTN_YN
        , ENPR_INRD_CON
        , CREW_RTRV
        , RGSN_USER_ID
        , RGSN_TS
        , AMNN_USER_ID
        , AMNN_TS
    )
    VALUES
    (
        #{utlinsttId}
        , #{enfmClsfCd}
        , #{enprDsncClsfCd}
        , #{bsunDwarCd}
        , #{empCnt}
        , #{btnm}
        , #{bzstNm}
        , #{msrnAmslYear}
        , #{msrnAmslAmt}
        , #{lstnYn}
        , #{enprInrdCon}
        , 0
        , #{rgsnUserId}
        , CURRENT_TIMESTAMP
        , #{amnnUserId}
        , CURRENT_TIMESTAMP
    )

