mapper.update:
UPDATE
    TB_BOX_IVT_ENPR_PRDT_L
SET
    PRDT_NM            = #{prdtNm}
    , PRDT_PTRN          = #{prdtPtrn}
    , PRDT_IMG_FILE_ID   = #{fileId}
    , PRDT_DESC          = #{prdtDesc}
    , PRDT_CHRC          = #{prdtChrc}
    , AMNN_USER_ID       = #{amnnUserId}
    , AMNN_TS            = CURRENT_TIMESTAMP
WHERE
    UTLINSTT_ID = #{utlinsttId}
    AND PRDT_ID = #{prdtId}

UPDATE
    TB_BOX_IVT_INVM_HOPE_D
SET
    INVM_STG_CD        = #{invmStgCd}
    , INVM_AMT_CD        = #{invmAmtCd}
    , OPPB_YN            = #{oppbYn}

    , AMNN_USER_ID     = #{amnnUserId}
    , AMNN_TS          = CURRENT_TIMESTAMP


    , OSIV_HOPEYN      = #{osivHopeyn}
WHERE
    UTLINSTT_ID = #{utlinsttId}

UPDATE
    TB_BOX_IVT_ENPR_TMMB_L
SET
    TMMB_NM          = #{tmmbNm}
    , TMMB_JBCL        = #{tmmbJbcl}
    , CRR_CON          = #{crrCon}
    , TMMB_IMG_FILE_ID = #{fileId}
    , AMNN_USER_ID     = #{amnnUserId}
    , AMNN_TS          = #{amnnTs}
WHERE
    UTLINSTT_ID = #{utlinsttId} AND TMMB_ID = #{tmmbId}

UPDATE
    TB_BOX_IVT_ENPR_PRDT_L
SET
    DEL_YN                = 'Y'
    , AMNN_USER_ID       = #{amnnUserId}
    , AMNN_TS            = CURRENT_TIMESTAMP
WHERE
    UTLINSTT_ID = #{utlinsttId}
    AND PRDT_ID = #{prdtId}
